```typescript
const client = createZocketClient<AppRouter>("ws://localhost:3000", {
  headers: {
    authorization: "Bearer token123",
  },
  onOpen: () => console.log("Connected"),
  onClose: () => console.log("Disconnected"),
  debug: process.env.NODE_ENV === "development",
});
```

